def Pred (G : CDMG Node) (lt : Node → Node → Prop) (v : Node) : Set Node :=
  {w | w ∈ G ∧ lt w v}

def PredLE (G : CDMG Node) (lt : Node → Node → Prop) (v : Node) : Set Node :=
  G.Pred lt v ∪ {v}

